import React, { useState, useEffect, useCallback } from 'react';
import './CreateCombinedMaterial.css'; // Import CSS for styling

const EditCombinedMaterial = ({
    onClose,
    fetchAPI,
    apiBaseUrl,
    materialId, // Pass the materialId of the material you want to edit
}) => {
    // Initialize state
    const [comboMat, setComboMat] = useState({
        name: '',
        description: '',
        submaterials: [],
    });
    const [error, setError] = useState(null);
    const [materials, setMaterials] = useState([]);
    const [materialChanges, setMaterialChanges] = useState([]);

    const fetchData = useCallback(async () => {
        try {
            // Fetch the details of the material you want to edit
            const materialData = await fetchAPI(`${apiBaseUrl}/combinedMaterials/${materialId}`);
            
            // Fetch other necessary data (e.g., material list, material changes)
            const MaterialData = await fetchAPI(`${apiBaseUrl}/materiallist`);
            const materialChangesData = await fetchAPI(`${apiBaseUrl}/materialchangesAPI`);
            
            // Set the state with the fetched data
            setComboMat(materialData);
            setMaterials(MaterialData);
            setMaterialChanges(materialChangesData);
        } catch (error) {
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl, materialId]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    // Define event handlers (similar to your CombinedMaterialInputForm)

    const handleChange = (e) => {
        const { name, value } = e.target;
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            [name]: value,
        }));
    };

    const handleSubmaterialChange = async (index, field, value) => {
        // Similar to your CombinedMaterialInputForm
    };

    const saveEditedMaterial = async () => {
        try {
            const payload = {
                name: comboMat.name,
                description: comboMat.description,
                submaterials: comboMat.submaterials,
            };
            // Send a PUT request to update the material
            await fetchAPI(`${apiBaseUrl}/combinedMaterials/${materialId}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(payload),
            });
            alert('Material edited successfully!');
            onClose();
        } catch (error) {
            alert(`Error: ${error.message}`);
        }
    };

    // Other functions like addMaterial, removeMaterial can remain the same if needed

    if (error) return <div>Error: {error}</div>;

    return (
        <div className="material-input-form">
            <h3>Edit Material</h3>
            <span className="close-popup" onClick={onClose}>
                &times;
            </span>
            {/* Render the form with pre-filled data from comboMat state */}
            {/* Similar to your CombinedMaterialInputForm */}
            <button className="btn btn-success save-btn" onClick={saveEditedMaterial}>
                Save Edited Material
            </button>
        </div>
    );
};

export default EditCombinedMaterial;
